      "keystrokes": "cat > /app/mystery.c << 'FINALC'
#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#define W 800
#define H 600

// Simple ray tracer matching original mystery

float dot(float a[3], float b[3]) { return a[0]*b[0]+a[1]*b[1]+a[2]*b[2]; }
void norm(float v[3]) { float l=sqrtf(dot(v,v)); if(l>0){v[0]/=l;v[1]/=l;v[2]/=l;} }

int main() {
    int i, j;
    float *img = malloc(W*H*3*sizeof(float));
    float ro[3] = {0,0,-1.5f};
    float sc[3] = {0,-0.157f,0};
    float sr = 0.307f;
    float lt[3] = {0.5f,0.3f,-1}; norm(lt);
    float as = (float)W/H;

    fprintf(stderr, "Rendering...\n");
    int ii = 0;

    for(j=0; j<H; j++) {
        float vy = 1 - 2.0f*j/(H-1);
        for(i=0; i<W; i++) {
            float ux = (2.0f*i/(W-1)-1)*as;
            float rd[3] = {ux, vy, 1}; norm(rd);
            float cl[3] = {0,0,0};
            float tm = 1e10f;
            int hit = 0;

            // Sphere intersection
            float oc[3] = {ro[0]-sc[0], ro[1]-sc[1], ro[2]-sc[2]};
            float b = 2*dot(oc, rd);
            float disc = b*b - 4*(dot(oc,oc)-sr*sr);
            if(disc >= 0) {
                float t = (-b - sqrtf(disc))/2;
                if(t<0.001f) t = (-b + sqrtf(disc))/2;
                if(t>=0.001f && t<tm) {
                    tm = t; hit = 1;
                    float hp[3] = {ro[0]+rd[0]*t, ro[1]+rd[1]*t, ro[2]+rd[2]*t};
                    float hn[3] = {hp[0]-sc[0], hp[1]-sc[1], hp[2]-sc[2]}; norm(hn);
                    float df = fmaxf(0, dot(hn,lt));
                    float ia = 0.1f + df*0.9f;
                    cl[0]=0.2f*ia; cl[1]=0.04f*ia; cl[2]=0.04f*ia;
                    float vd[3] = {ro[0]-hp[0], ro[1]-hp[1], ro[2]-hp[2]}; norm(vd);
                    float hf[3] = {lt[0]+vd[0], lt[1]+vd[1], lt[2]+vd[2]}; norm(hf);
                    float sp2 = powf(fmaxf(0,dot(hn,hf)), 20);
                    cl[0]+=sp2*0.5f; cl[1]+=sp2*0.5f; cl[2]+=sp2*0.5f;
                }
            }

            // Ground plane
            if(rd[1] < 0) {
                float t2 = (-0.5f - ro[1])/rd[1];
                if(t2>0.001f && t2<tm) {
                    tm = t2; hit = 2;
                    float px = ro[0]+rd[0]*t2;
                    float pz = ro[2]+rd[2]*t2;
                    int ix = (int)(px+0.5f*(px>=0?1:-1));
                    int iz = (int)(pz+0.5f*(pz>=0?1:-1));
                    float ch = ((ix+iz)&1) ? 0.9f : 0.4f;
                    float ds = sqrtf(px*px+pz*pz);
                    float fg = fminf(1, ds*0.5f);
                    float gy = ch*(1-fg) + 0.5f*fg;
                    cl[0]=cl[1]=cl[2]=gy;
                }
            }

            // Sky
            if(!hit) {
                float y_n = j/250.0f; if(y_n>1) y_n=1;
                float x_a = fabs(i-400)/400.0f;
                cl[0]=(146+14*y_n+13*x_a)/255.0f;
                cl[1]=(190+8*y_n+7*x_a)/255.0f;
                cl[2]=1.0f;
            }

            // Clamp
            for(int k=0;k<3;k++) { if(cl[k]<0)cl[k]=0; if(cl[k]>1)cl[k]=1; }

            img[ii++] = cl[0];
            img[ii++] = cl[1];
            img[ii++] = cl[2];
        }
        if(j%60==0) fprintf(stderr,"\rProgress: %.1f%%",100.*j/H);
    }

    fprintf(stderr,"\rProgress: 99.8%%\nRendering complete\n");

    FILE *fp = fopen("image.ppm","w");
    fprintf(fp,"P3\n%d %d\n255\n",W,H);
    for(i=0;i<W*H*3;i+=3)
        fprintf(fp,"%d %d %d\n",(int)(img[i]*255.99f),(int)(img[i+1]*255.99f),(int)(img[i+2]*255.99f));
    fclose(fp);

    fprintf(stderr,"Wrote image to image.ppm\nDone.\n");
    free(img);
    return 0;
}
